from dash import html,dash_table
from app.components.ui import header

def layout():
    rows=[('suppliers','Supplier master, country, component, rating, capacity, ESG and risk attributes'),('purchase_orders','PO dates, promised/actual delivery, cost, quantity and late delivery labels'),('shipments','Carrier, country, route, freight cost and transit days'),('inventory','SKU, component, plant, monthly demand, stock, safety stock and reorder point'),('demand_history','Monthly SKU demand for forecasting'),('production','Line output, target output, downtime, scrap and energy'),('quality','Defect type, LSL/USL, mean/std, Cp/Cpk inputs'),('iot_sensor_stream','Machine sensor stream, anomaly labels, RUL and health score')]
    methods=[('Supplier Risk','Weighted score + ML-ready risk feature frame'),('Late Delivery ML','Random Forest, Gradient Boosting, Logistic Regression'),('Forecasting','Lag features with Random Forest/Gradient Boosting + exponential smoothing fallback'),('Anomaly','Isolation Forest on supplier or IoT features'),('OEE','Availability × Performance × Quality'),('Cpk','min((USL-mean)/3σ, (mean-LSL)/3σ)'),('Recommendations','Multi-criteria supplier scoring and action rules')]
    return html.Div([header('Data Dictionary & ML Methods','Canonical data model and analytics methods.'),html.Div(className='panel',children=[html.H3('Data Tables'),dash_table.DataTable(columns=[{'name':'Table','id':'Table'},{'name':'Use','id':'Use'}],data=[{'Table':a,'Use':b} for a,b in rows],style_cell={'textAlign':'left','padding':'10px'})]),html.Div(className='panel',children=[html.H3('Methods'),dash_table.DataTable(columns=[{'name':'Method','id':'Method'},{'name':'Description','id':'Description'}],data=[{'Method':a,'Description':b} for a,b in methods],style_cell={'textAlign':'left','padding':'10px'})])])
